var e=[{id:`L2_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`칫......! 내가 왜 이런 짓을 하고 있는 거람?`,JPN:`チッ……！　なんで私がこんなことしなきゃいけないの？`,ENG:`Hmpf! What the heck am I doing here?`,TWN:`切……！我還得做這些事？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`으이씨......! 그래도 얼굴 아는 사이인데 괜히 죽기라도 했으면 찜찜하잖아!`,JPN:`もう……！　なんだかんだ顔見知りだし、ここで見殺しにしたら気まずいじゃない！`,ENG:`Ugh! Still, I guess I'll feel kind of bad if she dies on me... given how much time we've spent together!`,TWN:`額啊……！不過好歹是認識的人，她死了我的心裡也不舒服啊！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`여엉차아앗?!`,JPN:`どりゃああああ！！`,ENG:`Heave-ho?!`,TWN:`嘿咻？！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`하아...... 하아......`,JPN:`はあ……はあ……`,ENG:`*Huff... Huff...*`,TWN:`哈啊……哈啊……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`릴리, 괜찮아? 일어설 수 있겠어?`,JPN:`リリー、大丈夫？　立てる？`,ENG:`Are you alright, Lily? Can you get up?`,TWN:`莉莉，沒事吧？能站起來嗎？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`......네.`,JPN:`……はい。`,ENG:`Yes.`,TWN:`……嗯。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`멍하니 무너지는 천장을 보고 있었는데...... 메이드장님이 구해 주셨어요.`,JPN:`呆然と崩れる天井を眺めていたら……メイド長が救ってくれました。`,ENG:`I was just staring blankly at the ceiling falling down on me... but then the Chief Maid saved me.`,TWN:`我愣著看天花板塌下來的時候……是女僕長救了我。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`저는, 저는 대체, 그동안 무슨 짓을......`,JPN:`私はこれまでなんてことを……`,ENG:`What... What have I been doing this whole time?`,TWN:`我、我到底，對她做了些什麼事……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`칭얼거릴 시간 없으니까 얼른 일어나!`,JPN:`グズグズする時間はないから早く立って！`,ENG:`There's no time to whine! Get up!`,TWN:`現在沒時間讓你任性，快起來！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`그레이 리픈지 호박잎인지 하는 녀석들이 계속 나타나고 있단 말이야!`,JPN:`グレーリーフなのか、カボチャの葉っぱなのか知らないけど、ずっと増えてるの！`,ENG:`Those freaky Gray Leaves or whatever keep popping out of nowhere!`,TWN:`格雷麗芙還是什麼的，她們不斷地冒出來了！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`여기서 죽기 싫으면 뭐든 도우라고!`,JPN:`ここで死にたくなければ何でもいいから手伝って！`,ENG:`You'd better help out if you don't want to croak here!`,TWN:`不想死就趕緊幫忙！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`알겠어요. 당신에게 훈계 받는 날이 올 줄은 몰랐네요.`,JPN:`わかりました。あなたに説教される日が来るとは思いもしませんでした。`,ENG:`Very well. I never knew the day would come when you'd be the one lecturing me.`,TWN:`知道了，沒想到有一天我會受你教訓。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`그런데, 메이드장님이 아끼던 그 아이는? 당신과 같이 있지 않았나요?`,JPN:`ところで、メイド長が大事にしていたあの子は？　あなたと一緒にいたのでは？`,ENG:`By the way, where is the child that the Chief Maid is fond of? Wasn't she with you?`,TWN:`對了，女僕長很在意的那個孩子呢？不是和你在一起嗎？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`어? 그러고 보니 진짜 없잖아?`,JPN:`あれ？　そういえばいない！`,ENG:`Huh? Oh, dang! She's gone!`,TWN:`額？對啊，她去哪裡了？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`SPEAR_MAID_NULL_NULL`,text:{KOREA:`야! 꼬맹이! 어디 있어?!`,JPN:`ねえ！　チビちゃん！　どこにいるの！？`,ENG:`Hey, kid! Where are you?`,TWN:`喂！小鬼！你在哪裡？！`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:{char_id:`SPEAR_MAID_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};